    codePath = analyzer.codePath = new CodePath({
      id: analyzer.idGenerator.next(),
      origin,
      upper: codePath,
      onLooped: analyzer.onLooped,
    });
    state = CodePath.getState(codePath);

    // Emits onCodePathStart events.
    analyzer.emitter.emit('onCodePathStart', codePath, node);
  }

description:
This is called on a code path looped.
Then this raises a looped event.
@param {CodePathSegment} fromSegment A segment of prev.
@param {CodePathSegment} toSegment A segment of next.
@returns {void}

code:
onLooped(fromSegment, toSegment) {
    if (fromSegment.reachable && toSegment.reachable) {
      this.emitter.emit(
        'onCodePathSegmentLoop',
        fromSegment,
        toSegment,
        this.currentNode,
      );
    }
  }

description:
@param {string} id An identifier.
@param {CodePathSegment[]} allPrevSegments An array of the previous segments.
This array includes unreachable segments.
@param {boolean} reachable A flag which shows this is reachable.

code:
constructor(id, allPrevSegments, reachable) {
    /**
     * The identifier of this code path.
     * Rules use it to store additional information of each rule.
     * @type {string}
     */
    this.id = id;

    /**
     * An array of the next segments.
     * @type {CodePathSegment[]}
     */
    this.nextSegments = [];

    /**
     * An array of the previous segments.
     * @type {CodePathSegment[]}
     */
    this.prevSegments = allPrevSegments.filter(isReachable);

    /**
     * An array of the next segments.
     * This array includes unreachable segments.
     * @type {CodePathSegment[]}
     */
    this.allNextSegments = [];

    /**
     * An array of the previous segments.
     * This array includes unreachable segments.
     * @type {CodePathSegment[]}
     */
    this.allPrevSegments = allPrevSegments;

    /**
     * A flag which shows this is reachable.
     * @type {boolean}
     */
    this.reachable = reachable;

    // Internal data.
    Object.defineProperty(this, 'internal', {
      value: {
        used: false,
        loopedPrevSegments: [],
      },
    });
  }

description:
Creates a segment that follows given segments.
@param {string} id An identifier.
@param {CodePathSegment[]} allPrevSegments An array of the previous segments.
@returns {CodePathSegment} The created segment.

code:
static newNext(id, allPrevSegments) {
    return new CodePathSegment(
      id,
      CodePathSegment.flattenUnusedSegments(allPrevSegments),
      allPrevSegments.some(isReachable),
    );
  }

description:
Creates an unreachable segment that follows given segments.
@param {string} id An identifier.
@param {CodePathSegment[]} allPrevSegments An array of the previous segments.
@returns {CodePathSegment} The created segment.

code:
static newUnreachable(id, allPrevSegments) {
    const segment = new CodePathSegment(
      id,
      CodePathSegment.flattenUnusedSegments(allPrevSegments),
      false,
    );

    /*
     * In `if (a) return a; foo();` case, the unreachable segment preceded by
     * the return statement is not used but must not be remove.
     */
    CodePathSegment.markUsed(segment);

    return segment;
  }

description:
Makes a given segment being used.

And this function registers the segment into the previous segments as a next.
@param {CodePathSegment} segment A segment to mark.
@returns {void}

code:
static markUsed(segment) {
    if (segment.internal.used) {
      return;
    }
    segment.internal.used = true;

    let i;

    if (segment.reachable) {
      for (i = 0; i < segment.allPrevSegments.length; ++i) {
        const prevSegment = segment.allPrevSegments[i];

        prevSegment.allNextSegments.push(segment);
        prevSegment.nextSegments.push(segment);
      }
    } else {
      for (i = 0; i < segment.allPrevSegments.length; ++i) {
        segment.allPrevSegments[i].allNextSegments.push(segment);
      }
    }
  }

description:
Replaces unused segments with the previous segments of each unused segment.
@param {CodePathSegment[]} segments An array of segments to replace.
@returns {CodePathSegment[]} The replaced array.

code:
static flattenUnusedSegments(segments) {
    const done = Object.create(null);
    const retv = [];

    for (let i = 0; i < segments.length; ++i) {
      const segment = segments[i];

      // Ignores duplicated.
      if (done[segment.id]) {
        continue;
      }

      // Use previous segments if unused.
      if (!segment.internal.used) {
        for (let j = 0; j < segment.allPrevSegments.length; ++j) {
          const prevSegment = segment.allPrevSegments[j];

          if (!done[prevSegment.id]) {
            done[prevSegment.id] = true;
            retv.push(prevSegment);
          }
        }
      } else {
        done[segment.id] = true;
        retv.push(segment);
      }
    }

    return retv;
  }

description:
Gets a context for a `return` statement.
@param {CodePathState} state A state to get.
@returns {TryContext|CodePathState} A context for a `return` statement.

code:
function getReturnContext(state) {
  let context = state.tryContext;

  while (context) {
    if (context.hasFinalizer && context.position !== 'finally') {
      return context;
    }
    context = context.upper;
  }

  return state;
}

description:
Makes a code path segment of the right-hand operand of a logical
expression.
@throws {Error} (Unreachable.)
@returns {void}

code:
makeLogicalRight() {
    const context = this.choiceContext;
    const forkContext = this.forkContext;

    if (context.processed) {
      /*
       * This got segments already from the child choice context.
       * Creates the next path from own true/false fork context.
       */
      let prevForkContext;

      switch (context.kind) {
        case '&&': // if true then go to the right-hand side.
          prevForkContext = context.trueForkContext;
          break;
        case '||': // if false then go to the right-hand side.
          prevForkContext = context.falseForkContext;
          break;
        case '??': // Both true/false can short-circuit, so needs the third path to go to the right-hand side. That's qqForkContext.
          prevForkContext = context.qqForkContext;
          break;
        default:
          throw new Error('unreachable');
      }

      forkContext.replaceHead(prevForkContext.makeNext(0, -1));
      prevForkContext.clear();
      context.processed = false;
    } else {
      /*
       * This did not get segments from the child choice context.
       * So addresses the head segments.
       * The head segments are the path of the left-hand operand.
       */
      switch (context.kind) {
        case '&&': // the false path can short-circuit.
          context.falseForkContext.add(forkContext.head);
          break;
        case '||': // the true path can short-circuit.
          context.trueForkContext.add(forkContext.head);
          break;
        case '??': // both can short-circuit.
          context.trueForkContext.add(forkContext.head);
          context.falseForkContext.add(forkContext.head);
          break;
        default:
          throw new Error('unreachable');
      }

      forkContext.replaceHead(forkContext.makeNext(-1, -1));
    }
  }

makeIfConsequent() {
    const context = this.choiceContext;
    const forkContext = this.forkContext;

    /*
     * If any result were not transferred from child contexts,
     * this sets the head segments to both cases.
     * The head segments are the path of the test expression.
     */
    if (!context.processed) {
      context.trueForkContext.add(forkContext.head);
      context.falseForkContext.add(forkContext.head);
      context.qqForkContext.add(forkContext.head);
    }

    context.processed = false;

    // Creates new path from the `true` case.
    forkContext.replaceHead(context.trueForkContext.makeNext(0, -1));
  }

makeIfAlternate() {
    const context = this.choiceContext;
    const forkContext = this.forkContext;

    /*
     * The head segments are the path of the `if` block.
     * Updates the `true` path with the end of the `if` block.
     */
    context.trueForkContext.clear();
    context.trueForkContext.add(forkContext.head);
    context.processed = true;

    // Creates new path from the `false` case.
    forkContext.replaceHead(context.falseForkContext.makeNext(0, -1));
  }

description:
Creates a context object of TryStatement and stacks it.
@param {boolean} hasFinalizer `true` if the try statement has a
`finally` block.
@returns {void}

code:
pushTryContext(hasFinalizer) {
    this.tryContext = {
      upper: this.tryContext,
      position: 'try',
      hasFinalizer,

      returnedForkContext: hasFinalizer
        ? ForkContext.newEmpty(this.forkContext)
        : null,

      thrownForkContext: ForkContext.newEmpty(this.forkContext),
      lastOfTryIsReachable: false,
      lastOfCatchIsReachable: false,
    };
  }

makeCatchBlock() {
    const context = this.tryContext;
    const forkContext = this.forkContext;
    const thrown = context.thrownForkContext;

    // Update state.
    context.position = 'catch';
    context.thrownForkContext = ForkContext.newEmpty(forkContext);
    context.lastOfTryIsReachable = forkContext.reachable;

    // Merge thrown paths.
    thrown.add(forkContext.head);
    const thrownSegments = thrown.makeNext(0, -1);

    // Fork to a bypass and the merged thrown path.
    this.pushForkContext();
    this.forkBypassPath();
    this.forkContext.add(thrownSegments);
  }

description:
Makes a code path segment from the first throwable node to the `catch`
block or the `finally` block.
@returns {void}

code:
makeFirstThrowablePathInTryBlock() {
    const forkContext = this.forkContext;

    if (!forkContext.reachable) {
      return;
    }

    const context = getThrowContext(this);

    if (
      context === this ||
      context.position !== 'try' ||
      !context.thrownForkContext.empty
    ) {
      return;
    }

    context.thrownForkContext.add(forkContext.head);
    forkContext.replaceHead(forkContext.makeNext(-1, -1));
  }

description:
Makes a code path segment for the test part of a ForStatement.
@param {boolean|undefined} test The test value (only when constant).
@returns {void}

code:
makeForTest(test) {
    const context = this.loopContext;
    const forkContext = this.forkContext;
    const endOfInitSegments = forkContext.head;
    const testSegments = forkContext.makeNext(-1, -1);

    // Update state.
    context.test = test;
    context.endOfInitSegments = endOfInitSegments;
    context.continueDestSegments = context.testSegments = testSegments;
    forkContext.replaceHead(testSegments);
  }

makeForBody() {
    const context = this.loopContext;
    const choiceContext = this.choiceContext;
    const forkContext = this.forkContext;

    // Update state.
    if (context.updateSegments) {
      context.endOfUpdateSegments = forkContext.head;

      // `update` -> `test`
      if (context.testSegments) {
        makeLooped(this, context.endOfUpdateSegments, context.testSegments);
      }
    } else if (context.testSegments) {
      finalizeTestSegmentsOfFor(context, choiceContext, forkContext.head);
    } else {
      context.endOfInitSegments = forkContext.head;
    }

    let bodySegments = context.endOfTestSegments;

    if (!bodySegments) {
      /*
       * If there is not the `test` part, the `body` path comes from the
       * `init` part and the `update` part.
       */
      const prevForkContext = ForkContext.newEmpty(forkContext);

      prevForkContext.add(context.endOfInitSegments);
      if (context.endOfUpdateSegments) {
        prevForkContext.add(context.endOfUpdateSegments);
      }

      bodySegments = prevForkContext.makeNext(0, -1);
    }
    context.continueDestSegments = context.continueDestSegments || bodySegments;
    forkContext.replaceHead(bodySegments);
  }

description:
Makes a code path segment for the test part of a DoWhileStatement.
@param {boolean|undefined} test The test value (only when constant).
@returns {void}

code:
makeDoWhileTest(test) {
    const context = this.loopContext;
    const forkContext = this.forkContext;

    context.test = test;

    // Creates paths of `continue` statements.
    if (!context.continueForkContext.empty) {
      context.continueForkContext.add(forkContext.head);
      const testSegments = context.continueForkContext.makeNext(0, -1);

      forkContext.replaceHead(testSegments);
    }
  }

description:
Makes a path for a `break` statement.

It registers the head segment to a context of `break`.
It makes new unreachable segment, then it set the head with the segment.
@param {string} label A label of the break statement.
@returns {void}

code:
makeBreak(label) {
    const forkContext = this.forkContext;

    if (!forkContext.reachable) {
      return;
    }

    const context = getBreakContext(this, label);

    if (context) {
      context.brokenForkContext.add(forkContext.head);
    }

    /* c8 ignore next */
    forkContext.replaceHead(forkContext.makeUnreachable(-1, -1));
  }

popBreakContext() {
    const context = this.breakContext;
    const forkContext = this.forkContext;

    this.breakContext = context.upper;

    // Process this context here for other than switches and loops.
    if (!context.breakable) {
      const brokenForkContext = context.brokenForkContext;

      if (!brokenForkContext.empty) {
        brokenForkContext.add(forkContext.head);
        forkContext.replaceHead(brokenForkContext.makeNext(0, -1));
      }
    }

    return context;
  }

description:
Creates new context for BreakStatement.
@param {boolean} breakable The flag to indicate it can break by
an unlabeled BreakStatement.
@param {string|null} label The label of this context.
@returns {Object} The new context.

code:
pushBreakContext(breakable, label) {
    this.breakContext = {
      upper: this.breakContext,
      breakable,
      label,
      brokenForkContext: ForkContext.newEmpty(this.forkContext),
    };
    return this.breakContext;
  }

description:
Adds given segments into the `dest` array.
If the `others` array does not includes the given segments, adds to the `all`
array as well.

This adds only reachable and used segments.
@param {CodePathSegment[]} dest A destination array (`returnedSegments` or `thrownSegments`).
@param {CodePathSegment[]} others Another destination array (`returnedSegments` or `thrownSegments`).
@param {CodePathSegment[]} all The unified destination array (`finalSegments`).
@param {CodePathSegment[]} segments Segments to add.
@returns {void}

code:
function addToReturnedOrThrown(dest, others, all, segments) {
  for (let i = 0; i < segments.length; ++i) {
    const segment = segments[i];

    dest.push(segment);
    if (!others.includes(segment)) {
      all.push(segment);
    }
  }
}

description:
Gets a context for a `break` statement.
@param {CodePathState} state A state to get.
@param {string} label The label of a `break` statement.
@returns {LoopContext|SwitchContext} A context for a `break` statement.

code:
function getBreakContext(state, label) {
  let context = state.breakContext;

  while (context) {
    if (label ? context.label === label : context.breakable) {
      return context;
    }
    context = context.upper;
  }

  /* c8 ignore next */
  return null;
}

description:
The parent forking context.
This is used for the root of new forks.
@type {ForkContext}

code:
get parentForkContext() {
    const current = this.forkContext;

    return current && current.upper;
  }

description:
Creates a context for ConditionalExpression, LogicalExpression, AssignmentExpression (logical assignments only),
IfStatement, WhileStatement, DoWhileStatement, or ForStatement.

LogicalExpressions have cases that it goes different paths between the
`true` case and the `false` case.

For Example:

if (a || b) {
foo();
} else {
bar();
}

In this case, `b` is evaluated always in the code path of the `else`
block, but it's not so in the code path of the `if` block.
So there are 3 paths.

a -> foo();
a -> b -> foo();
a -> b -> bar();
@param {string} kind A kind string.
If the new context is LogicalExpression's or AssignmentExpression's, this is `"&&"` or `"||"` or `"??"`.
If it's IfStatement's or ConditionalExpression's, this is `"test"`.
Otherwise, this is `"loop"`.
@param {boolean} isForkingAsResult A flag that shows that goes different
paths between `true` and `false`.
@returns {void}

code:
pushChoiceContext(kind, isForkingAsResult) {
    this.choiceContext = {
      upper: this.choiceContext,
      kind,
      isForkingAsResult,
      trueForkContext: ForkContext.newEmpty(this.forkContext),
      falseForkContext: ForkContext.newEmpty(this.forkContext),
      qqForkContext: ForkContext.newEmpty(this.forkContext),
      processed: false,
    };
  }

description:
Creates a context object of SwitchStatement and stacks it.
@param {boolean} hasCase `true` if the switch statement has one or more
case parts.
@param {string|null} label The label text.
@returns {void}

code:
pushSwitchContext(hasCase, label) {
    this.switchContext = {
      upper: this.switchContext,
      hasCase,
      defaultSegments: null,
      defaultBodySegments: null,
      foundDefault: false,
      lastIsDefault: false,
      countForks: 0,
    };

    this.pushBreakContext(true, label);
  }

description:
Pops the last context of SwitchStatement and finalizes it.

- Disposes all forking stack for `case` and `default`.
- Creates the next code path segment from `context.brokenForkContext`.
- If the last `SwitchCase` node is not a `default` part, creates a path
to the `default` body.
@returns {void}

code:
popSwitchContext() {
    const context = this.switchContext;

    this.switchContext = context.upper;

    const forkContext = this.forkContext;
    const brokenForkContext = this.popBreakContext().brokenForkContext;

    if (context.countForks === 0) {
      /*
       * When there is only one `default` chunk and there is one or more
       * `break` statements, even if forks are nothing, it needs to merge
       * those.
       */
      if (!brokenForkContext.empty) {
        brokenForkContext.add(forkContext.makeNext(-1, -1));
        forkContext.replaceHead(brokenForkContext.makeNext(0, -1));
      }

      return;
    }

    const lastSegments = forkContext.head;

    this.forkBypassPath();
    const lastCaseSegments = forkContext.head;

    /*
     * `brokenForkContext` is used to make the next segment.
     * It must add the last segment into `brokenForkContext`.
     */
    brokenForkContext.add(lastSegments);

    /*
     * A path which is failed in all case test should be connected to path
     * of `default` chunk.
     */
    if (!context.lastIsDefault) {
      if (context.defaultBodySegments) {
        /*
         * Remove a link from `default` label to its chunk.
         * It's false route.
         */
        removeConnection(context.defaultSegments, context.defaultBodySegments);
        makeLooped(this, lastCaseSegments, context.defaultBodySegments);
      } else {
        /*
         * It handles the last case body as broken if `default` chunk
         * does not exist.
         */
        brokenForkContext.add(lastCaseSegments);
      }
    }

    // Pops the segment context stack until the entry segment.
    for (let i = 0; i < context.countForks; ++i) {
      this.forkContext = this.forkContext.upper;
    }

    /*
     * Creates a path from all brokenForkContext paths.
     * This is a path after switch statement.
     */
    this.forkContext.replaceHead(brokenForkContext.makeNext(0, -1));
  }

popTryContext() {
    const context = this.tryContext;

    this.tryContext = context.upper;

    if (context.position === 'catch') {
      // Merges two paths from the `try` block and `catch` block merely.
      this.popForkContext();
      return;
    }

    /*
     * The following process is executed only when there is the `finally`
     * block.
     */

    const returned = context.returnedForkContext;
    const thrown = context.thrownForkContext;

    if (returned.empty && thrown.empty) {
      return;
    }

    // Separate head to normal paths and leaving paths.
    const headSegments = this.forkContext.head;

    this.forkContext = this.forkContext.upper;
    const normalSegments = headSegments.slice(0, (headSegments.length / 2) | 0);
    const leavingSegments = headSegments.slice((headSegments.length / 2) | 0);

    // Forwards the leaving path to upper contexts.
    if (!returned.empty) {
      getReturnContext(this).returnedForkContext.add(leavingSegments);
    }
    if (!thrown.empty) {
      getThrowContext(this).thrownForkContext.add(leavingSegments);
    }

    // Sets the normal path as the next.
    this.forkContext.replaceHead(normalSegments);

    /*
     * If both paths of the `try` block and the `catch` block are
     * unreachable, the next path becomes unreachable as well.
     */
    if (!context.lastOfTryIsReachable && !context.lastOfCatchIsReachable) {
      this.forkContext.makeUnreachable();
    }
  }

description:
Makes a code path segment for the test part of a WhileStatement.
@param {boolean|undefined} test The test value (only when constant).
@returns {void}

code:
makeWhileTest(test) {
    const context = this.loopContext;
    const forkContext = this.forkContext;
    const testSegments = forkContext.makeNext(0, -1);

    // Update state.
    context.test = test;
    context.continueDestSegments = testSegments;
    forkContext.replaceHead(testSegments);
  }

makeForUpdate() {
    const context = this.loopContext;
    const choiceContext = this.choiceContext;
    const forkContext = this.forkContext;

    // Make the next paths of the test.
    if (context.testSegments) {
      finalizeTestSegmentsOfFor(context, choiceContext, forkContext.head);
    } else {
      context.endOfInitSegments = forkContext.head;
    }

    // Update state.
    const updateSegments = forkContext.makeDisconnected(-1, -1);

    context.continueDestSegments = context.updateSegments = updateSegments;
    forkContext.replaceHead(updateSegments);
  }

description:
Makes a path for a `return` statement.

It registers the head segment to a context of `return`.
It makes new unreachable segment, then it set the head with the segment.
@returns {void}

code:
makeReturn() {
    const forkContext = this.forkContext;

    if (forkContext.reachable) {
      getReturnContext(this).returnedForkContext.add(forkContext.head);
      forkContext.replaceHead(forkContext.makeUnreachable(-1, -1));
    }
  }

description:
Makes a path for a `continue` statement.

It makes a looping path.
It makes new unreachable segment, then it set the head with the segment.
@param {string} label A label of the continue statement.
@returns {void}

code:
makeContinue(label) {
    const forkContext = this.forkContext;

    if (!forkContext.reachable) {
      return;
    }

    const context = getContinueContext(this, label);

    if (context) {
      if (context.continueDestSegments) {
        makeLooped(this, forkContext.head, context.continueDestSegments);

        // If the context is a for-in/of loop, this effects a break also.
        if (
          context.type === 'ForInStatement' ||
          context.type === 'ForOfStatement'
        ) {
          context.brokenForkContext.add(forkContext.head);
        }
      } else {
        context.continueForkContext.add(forkContext.head);
      }
    }
    forkContext.replaceHead(forkContext.makeUnreachable(-1, -1));
  }

description:
Gets a context for a `throw` statement.
@param {CodePathState} state A state to get.
@returns {TryContext|CodePathState} A context for a `throw` statement.

code:
function getThrowContext(state) {
  let context = state.tryContext;

  while (context) {
    if (
      context.position === 'try' ||
      (context.hasFinalizer && context.position === 'catch')
    ) {
      return context;
    }
    context = context.upper;
  }

  return state;
}

description:
Gets a loop-context for a `continue` statement.
@param {CodePathState} state A state to get.
@param {string} label The label of a `continue` statement.
@returns {LoopContext} A loop-context for a `continue` statement.

code:
function getContinueContext(state, label) {
  if (!label) {
    return state.loopContext;
  }

  let context = state.loopContext;

  while (context) {
    if (context.label === label) {
      return context;
    }
    context = context.upper;
  }

  /* c8 ignore next */
  return null;
}

description:
Disconnect given segments.

This is used in a process for switch statements.
If there is the "default" chunk before other cases, the order is different
between node's and running's.
@param {CodePathSegment[]} prevSegments Forward segments to disconnect.
@param {CodePathSegment[]} nextSegments Backward segments to disconnect.
@returns {void}

code:
function removeConnection(prevSegments, nextSegments) {
  for (let i = 0; i < prevSegments.length; ++i) {
    const prevSegment = prevSegments[i];
    const nextSegment = nextSegments[i];

    remove(prevSegment.nextSegments, nextSegment);
    remove(prevSegment.allNextSegments, nextSegment);
    remove(nextSegment.prevSegments, prevSegment);
    remove(nextSegment.allPrevSegments, prevSegment);
  }
}

description:
Pops the last choice context and finalizes it.
@throws {Error} (Unreachable.)
@returns {ChoiceContext} The popped context.

code:
popChoiceContext() {
    const context = this.choiceContext;

    this.choiceContext = context.upper;

    const forkContext = this.forkContext;
    const headSegments = forkContext.head;

    switch (context.kind) {
      case '&&':
      case '||':
      case '??':
        /*
         * If any result were not transferred from child contexts,
         * this sets the head segments to both cases.
         * The head segments are the path of the right-hand operand.
         */
        if (!context.processed) {
          context.trueForkContext.add(headSegments);
          context.falseForkContext.add(headSegments);
          context.qqForkContext.add(headSegments);
        }

        /*
         * Transfers results to upper context if this context is in
         * test chunk.
         */
        if (context.isForkingAsResult) {
          const parentContext = this.choiceContext;

          parentContext.trueForkContext.addAll(context.trueForkContext);
          parentContext.falseForkContext.addAll(context.falseForkContext);
          parentContext.qqForkContext.addAll(context.qqForkContext);
          parentContext.processed = true;

          return context;
        }

        break;

      case 'test':
        if (!context.processed) {
          /*
           * The head segments are the path of the `if` block here.
           * Updates the `true` path with the end of the `if` block.
           */
          context.trueForkContext.clear();
          context.trueForkContext.add(headSegments);
        } else {
          /*
           * The head segments are the path of the `else` block here.
           * Updates the `false` path with the end of the `else`
           * block.
           */
          context.falseForkContext.clear();
          context.falseForkContext.add(headSegments);
        }

        break;

      case 'loop':
        /*
         * Loops are addressed in popLoopContext().
         * This is called from popLoopContext().
         */
        return context;

      /* c8 ignore next */
      default:
        throw new Error('unreachable');
    }

    // Merges all paths.
    const prevForkContext = context.trueForkContext;

    prevForkContext.addAll(context.falseForkContext);
    forkContext.replaceHead(prevForkContext.makeNext(0, -1));

    return context;
  }

popForkContext() {
    const lastContext = this.forkContext;

    this.forkContext = lastContext.upper;
    this.forkContext.replaceHead(lastContext.makeNext(0, -1));

    return lastContext;
  }

description:
Create a choice context for optional access.
This method is called on entering to each `(Call|Member)Expression[optional=true]` node.
This creates a choice context as similar to `LogicalExpression[operator="??"]` node.
@returns {void}

code:
makeOptionalNode() {
    if (this.chainContext) {
      this.chainContext.countChoiceContexts += 1;
      this.pushChoiceContext('??', false);
    }
  }

description:
Makes a code path segment for a `SwitchCase` node.
@param {boolean} isEmpty `true` if the body is empty.
@param {boolean} isDefault `true` if the body is the default case.
@returns {void}

code:
makeSwitchCaseBody(isEmpty, isDefault) {
    const context = this.switchContext;

    if (!context.hasCase) {
      return;
    }

    /*
     * Merge forks.
     * The parent fork context has two segments.
     * Those are from the current case and the body of the previous case.
     */
    const parentForkContext = this.forkContext;
    const forkContext = this.pushForkContext();

    forkContext.add(parentForkContext.makeNext(0, -1));

    /*
     * Save `default` chunk info.
     * If the `default` label is not at the last, we must make a path from
     * the last `case` to the `default` chunk.
     */
    if (isDefault) {
      context.defaultSegments = parentForkContext.head;
      if (isEmpty) {
        context.foundDefault = true;
      } else {
        context.defaultBodySegments = forkContext.head;
      }
    } else {
      if (!isEmpty && context.foundDefault) {
        context.foundDefault = false;
        context.defaultBodySegments = forkContext.head;
      }
    }

    context.lastIsDefault = isDefault;
    context.countForks += 1;
  }

description:
Makes a code path segment for the body part of a ForInStatement and a
ForOfStatement.
@returns {void}

code:
makeForInOfBody() {
    const context = this.loopContext;
    const forkContext = this.forkContext;
    const temp = ForkContext.newEmpty(forkContext);

    temp.add(context.endOfLeftSegments);
    const bodySegments = temp.makeNext(-1, -1);

    // Make a path: `right` -> `left`.
    makeLooped(this, forkContext.head, context.leftSegments);

    // Update state.
    context.brokenForkContext.add(forkContext.head);
    forkContext.replaceHead(bodySegments);
  }

makeWhileBody() {
    const context = this.loopContext;
    const choiceContext = this.choiceContext;
    const forkContext = this.forkContext;

    if (!choiceContext.processed) {
      choiceContext.trueForkContext.add(forkContext.head);
      choiceContext.falseForkContext.add(forkContext.head);
    }

    // Update state.
    if (context.test !== true) {
      context.brokenForkContext.addAll(choiceContext.falseForkContext);
    }
    forkContext.replaceHead(choiceContext.trueForkContext.makeNext(0, -1));
  }

description:
Makes a path for a `throw` statement.

It registers the head segment to a context of `throw`.
It makes new unreachable segment, then it set the head with the segment.
@returns {void}

code:
makeThrow() {
    const forkContext = this.forkContext;

    if (forkContext.reachable) {
      getThrowContext(this).thrownForkContext.add(forkContext.head);
      forkContext.replaceHead(forkContext.makeUnreachable(-1, -1));
    }
  }

makeFinal() {
    const segments = this.currentSegments;

    if (segments.length > 0 && segments[0].reachable) {
      this.returnedForkContext.add(segments);
    }
  }

description:
Creates looping path.
@param {CodePathState} state The instance.
@param {CodePathSegment[]} unflattenedFromSegments Segments which are source.
@param {CodePathSegment[]} unflattenedToSegments Segments which are destination.
@returns {void}

code:
function makeLooped(state, unflattenedFromSegments, unflattenedToSegments) {
  const fromSegments = CodePathSegment.flattenUnusedSegments(
    unflattenedFromSegments,
  );
  const toSegments = CodePathSegment.flattenUnusedSegments(
    unflattenedToSegments,
  );

  const end = Math.min(fromSegments.length, toSegments.length);

  for (let i = 0; i < end; ++i) {
    const fromSegment = fromSegments[i];
    const toSegment = toSegments[i];

    if (toSegment.reachable) {
      fromSegment.nextSegments.push(toSegment);
    }
    if (fromSegment.reachable) {
      toSegment.prevSegments.push(fromSegment);
    }
    fromSegment.allNextSegments.push(toSegment);
    toSegment.allPrevSegments.push(fromSegment);

    if (toSegment.allPrevSegments.length >= 2) {
      CodePathSegment.markPrevSegmentAsLooped(toSegment, fromSegment);
    }

    state.notifyLooped(fromSegment, toSegment);
  }
}

description:
Finalizes segments of `test` chunk of a ForStatement.

- Adds `false` paths to paths which are leaving from the loop.
- Sets `true` paths to paths which go to the body.
@param {LoopContext} context A loop context to modify.
@param {ChoiceContext} choiceContext A choice context of this loop.
@param {CodePathSegment[]} head The current head paths.
@returns {void}

code:
function finalizeTestSegmentsOfFor(context, choiceContext, head) {
  if (!choiceContext.processed) {
    choiceContext.trueForkContext.add(head);
    choiceContext.falseForkContext.add(head);
    choiceContext.qqForkContext.add(head);
  }

  if (context.test !== true) {
    context.brokenForkContext.addAll(choiceContext.falseForkContext);
  }
  context.endOfTestSegments = choiceContext.trueForkContext.makeNext(0, -1);
}

description:
@param {IdGenerator} idGenerator An id generator to generate id for code
path segments.
@param {Function} onLooped A callback function to notify looping.

code:
constructor(idGenerator, onLooped) {
    this.idGenerator = idGenerator;
    this.notifyLooped = onLooped;
    this.forkContext = ForkContext.newRoot(idGenerator);
    this.choiceContext = null;
    this.switchContext = null;
    this.tryContext = null;
    this.loopContext = null;
    this.breakContext = null;
    this.chainContext = null;

    this.currentSegments = [];
    this.initialSegment = this.forkContext.head[0];

    // returnedSegments and thrownSegments push elements into finalSegments also.
    const final = (this.finalSegments = []);
    const returned = (this.returnedForkContext = []);
    const thrown = (this.thrownForkContext = []);

    returned.add = addToReturnedOrThrown.bind(null, returned, thrown, final);
    thrown.add = addToReturnedOrThrown.bind(null, thrown, returned, final);
  }

description:
Push a new `ChainExpression` context to the stack.
This method is called on entering to each `ChainExpression` node.
This context is used to count forking in the optional chain then merge them on the exiting from the `ChainExpression` node.
@returns {void}

code:
pushChainContext() {
    this.chainContext = {
      upper: this.chainContext,
      countChoiceContexts: 0,
    };
  }

description:
Pop a `ChainExpression` context from the stack.
This method is called on exiting from each `ChainExpression` node.
This merges all forks of the last optional chaining.
@returns {void}

code:
popChainContext() {
    const context = this.chainContext;

    this.chainContext = context.upper;

    // pop all choice contexts of this.
    for (let i = context.countChoiceContexts; i > 0; --i) {
      this.popChoiceContext();
    }
  }

description:
Makes a code path segment for a `finally` block.

In the `finally` block, parallel paths are created. The parallel paths
are used as leaving-paths. The leaving-paths are paths from `return`
statements and `throw` statements in a `try` block or a `catch` block.
@returns {void}

code:
makeFinallyBlock() {
    const context = this.tryContext;
    let forkContext = this.forkContext;
    const returned = context.returnedForkContext;
    const thrown = context.thrownForkContext;
    const headOfLeavingSegments = forkContext.head;

    // Update state.
    if (context.position === 'catch') {
      // Merges two paths from the `try` block and `catch` block.
      this.popForkContext();
      forkContext = this.forkContext;

      context.lastOfCatchIsReachable = forkContext.reachable;
    } else {
      context.lastOfTryIsReachable = forkContext.reachable;
    }
    context.position = 'finally';

    if (returned.empty && thrown.empty) {
      // This path does not leave.
      return;
    }

    /*
     * Create a parallel segment from merging returned and thrown.
     * This segment will leave at the end of this finally block.
     */
    const segments = forkContext.makeNext(-1, -1);

    for (let i = 0; i < forkContext.count; ++i) {
      const prevSegsOfLeavingSegment = [headOfLeavingSegments[i]];

      for (let j = 0; j < returned.segmentsList.length; ++j) {
        prevSegsOfLeavingSegment.push(returned.segmentsList[j][i]);
      }
      for (let j = 0; j < thrown.segmentsList.length; ++j) {
        prevSegsOfLeavingSegment.push(thrown.segmentsList[j][i]);
      }

      segments.push(
        CodePathSegment.newNext(
          this.idGenerator.next(),
          prevSegsOfLeavingSegment,
        ),
      );
    }

    this.pushForkContext(true);
    this.forkContext.add(segments);
  }

description:
Creates a context object of a loop statement and stacks it.
@param {string} type The type of the node which was triggered. One of
`WhileStatement`, `DoWhileStatement`, `ForStatement`, `ForInStatement`,
and `ForStatement`.
@param {string|null} label A label of the node which was triggered.
@throws {Error} (Unreachable - unknown type.)
@returns {void}

code:
pushLoopContext(type, label) {
    const forkContext = this.forkContext;
    const breakContext = this.pushBreakContext(true, label);

    switch (type) {
      case 'WhileStatement':
        this.pushChoiceContext('loop', false);
        this.loopContext = {
          upper: this.loopContext,
          type,
          label,
          test: void 0,
          continueDestSegments: null,
          brokenForkContext: breakContext.brokenForkContext,
        };
        break;

      case 'DoWhileStatement':
        this.pushChoiceContext('loop', false);
        this.loopContext = {
          upper: this.loopContext,
          type,
          label,
          test: void 0,
          entrySegments: null,
          continueForkContext: ForkContext.newEmpty(forkContext),
          brokenForkContext: breakContext.brokenForkContext,
        };
        break;

      case 'ForStatement':
        this.pushChoiceContext('loop', false);
        this.loopContext = {
          upper: this.loopContext,
          type,
          label,
          test: void 0,
          endOfInitSegments: null,
          testSegments: null,
          endOfTestSegments: null,
          updateSegments: null,
          endOfUpdateSegments: null,
          continueDestSegments: null,
          brokenForkContext: breakContext.brokenForkContext,
        };
        break;

      case 'ForInStatement':
      case 'ForOfStatement':
        this.loopContext = {
          upper: this.loopContext,
          type,
          label,
          prevSegments: null,
          leftSegments: null,
          endOfLeftSegments: null,
          continueDestSegments: null,
          brokenForkContext: breakContext.brokenForkContext,
        };
        break;

      /* c8 ignore next */
      default:
        throw new Error(`unknown type: "${type}"`);
    }
  }

description:
Pops the last context of a loop statement and finalizes it.
@throws {Error} (Unreachable - unknown type.)
@returns {void}

code:
popLoopContext() {
    const context = this.loopContext;

    this.loopContext = context.upper;

    const forkContext = this.forkContext;
    const brokenForkContext = this.popBreakContext().brokenForkContext;

    // Creates a looped path.
    switch (context.type) {
      case 'WhileStatement':
      case 'ForStatement':
        this.popChoiceContext();
        makeLooped(this, forkContext.head, context.continueDestSegments);
        break;

      case 'DoWhileStatement': {
        const choiceContext = this.popChoiceContext();

        if (!choiceContext.processed) {
          choiceContext.trueForkContext.add(forkContext.head);
          choiceContext.falseForkContext.add(forkContext.head);
        }
        if (context.test !== true) {
          brokenForkContext.addAll(choiceContext.falseForkContext);
        }

        // `true` paths go to looping.
        const segmentsList = choiceContext.trueForkContext.segmentsList;

        for (let i = 0; i < segmentsList.length; ++i) {
          makeLooped(this, segmentsList[i], context.entrySegments);
        }
        break;
      }

      case 'ForInStatement':
      case 'ForOfStatement':
        brokenForkContext.add(forkContext.head);
        makeLooped(this, forkContext.head, context.leftSegments);
        break;

      /* c8 ignore next */
      default:
        throw new Error('unreachable');
    }

    // Go next.
    if (brokenForkContext.empty) {
      forkContext.replaceHead(forkContext.makeUnreachable(-1, -1));
    } else {
      forkContext.replaceHead(brokenForkContext.makeNext(0, -1));
    }
  }

makeDoWhileBody() {
    const context = this.loopContext;
    const forkContext = this.forkContext;
    const bodySegments = forkContext.makeNext(-1, -1);

    // Update state.
    context.entrySegments = bodySegments;
    forkContext.replaceHead(bodySegments);
  }

description:
Makes a code path segment for the left part of a ForInStatement and a
ForOfStatement.
@returns {void}

code:
makeForInOfLeft() {
    const context = this.loopContext;
    const forkContext = this.forkContext;
    const leftSegments = forkContext.makeDisconnected(-1, -1);

    // Update state.
    context.prevSegments = forkContext.head;
    context.leftSegments = context.continueDestSegments = leftSegments;
    forkContext.replaceHead(leftSegments);
  }

description:
Makes a code path segment for the right part of a ForInStatement and a
ForOfStatement.
@returns {void}

code:
makeForInOfRight() {
    const context = this.loopContext;
    const forkContext = this.forkContext;
    const temp = ForkContext.newEmpty(forkContext);

    temp.add(context.prevSegments);
    const rightSegments = temp.makeNext(-1, -1);

    // Update state.
    context.endOfLeftSegments = forkContext.head;
    forkContext.replaceHead(rightSegments);
  }

description:
Creates a new instance.
@param {Object} options Options for the function (see below).
@param {string} options.id An identifier.
@param {string} options.origin The type of code path origin.
@param {CodePath|null} options.upper The code path of the upper function scope.
@param {Function} options.onLooped A callback function to notify looping.

code:
constructor({id, origin, upper, onLooped}) {
    /**
     * The identifier of this code path.
     * Rules use it to store additional information of each rule.
     * @type {string}
     */
    this.id = id;

    /**
     * The reason that this code path was started. May be "program",
     * "function", "class-field-initializer", or "class-static-block".
     * @type {string}
     */
    this.origin = origin;

    /**
     * The code path of the upper function scope.
     * @type {CodePath|null}
     */
    this.upper = upper;

    /**
     * The code paths of nested function scopes.
     * @type {CodePath[]}
     */
    this.childCodePaths = [];

    // Initializes internal state.
    Object.defineProperty(this, 'internal', {
      value: new CodePathState(new IdGenerator(`${id}_`), onLooped),
    });

    // Adds this into `childCodePaths` of `upper`.
    if (upper) {
      upper.childCodePaths.push(this);
    }
  }

description:
Traverses all segments in this code path.

codePath.traverseSegments(function(segment, controller) {
// do something.
});

This method enumerates segments in order from the head.

The `controller` object has two methods.

- `controller.skip()` - Skip the following segments in this branch.
- `controller.break()` - Skip all following segments.
@param {Object} [options] Omittable.
@param {CodePathSegment} [options.first] The first segment to traverse.
@param {CodePathSegment} [options.last] The last segment to traverse.
@param {Function} callback A callback function.
@returns {void}

code:
traverseSegments(options, callback) {
    let resolvedOptions;
    let resolvedCallback;

    if (typeof options === 'function') {
      resolvedCallback = options;
      resolvedOptions = {};
    } else {
      resolvedOptions = options || {};
      resolvedCallback = callback;
    }

    const startSegment = resolvedOptions.first || this.internal.initialSegment;
    const lastSegment = resolvedOptions.last;

    let item = null;
    let index = 0;
    let end = 0;
    let segment = null;
    const visited = Object.create(null);
    const stack = [[startSegment, 0]];
    let skippedSegment = null;
    let broken = false;
    const controller = {
      skip() {
        if (stack.length <= 1) {
          broken = true;
        } else {
          skippedSegment = stack[stack.length - 2][0];
        }
      },
      break() {
        broken = true;
      },
    };

    /**
     * Checks a given previous segment has been visited.
     * @param {CodePathSegment} prevSegment A previous segment to check.
     * @returns {boolean} `true` if the segment has been visited.
     */
    function isVisited(prevSegment) {
      return (
        visited[prevSegment.id] || segment.isLoopedPrevSegment(prevSegment)
      );
    }

    while (stack.length > 0) {
      item = stack[stack.length - 1];
      segment = item[0];
      index = item[1];

      if (index === 0) {
        // Skip if this segment has been visited already.
        if (visited[segment.id]) {
          stack.pop();
          continue;
        }

        // Skip if all previous segments have not been visited.
        if (
          segment !== startSegment &&
          segment.prevSegments.length > 0 &&
          !segment.prevSegments.every(isVisited)
        ) {
          stack.pop();
          continue;
        }

        // Reset the flag of skipping if all branches have been skipped.
        if (skippedSegment && segment.prevSegments.includes(skippedSegment)) {
          skippedSegment = null;
        }
        visited[segment.id] = true;

        // Call the callback when the first time.
        if (!skippedSegment) {
          resolvedCallback.call(this, segment, controller);
          if (segment === lastSegment) {
            controller.skip();
          }
          if (broken) {
            break;
          }
        }
      }

      // Update the stack.
      end = segment.nextSegments.length - 1;
      if (index < end) {
        item[1] += 1;
        stack.push([segment.nextSegments[index], 0]);
      } else if (index === end) {
        item[0] = segment.nextSegments[index];
        item[1] = 0;
      } else {
        stack.pop();
      }
    }
  }

description:
`segments` becomes doubly in a `finally` block. Then if a code path exits by a
control statement (such as `break`, `continue`) from the `finally` block, the
destination's segments may be half of the source segments. In that case, this
merges segments.
@param {ForkContext} context An instance.
@param {CodePathSegment[]} segments Segments to merge.
@returns {CodePathSegment[]} The merged segments.

code:
function mergeExtraSegments(context, segments) {
  let currentSegments = segments;

  while (currentSegments.length > context.count) {
    const merged = [];

    for (
      let i = 0, length = (currentSegments.length / 2) | 0;
      i < length;
      ++i
    ) {
      merged.push(
        CodePathSegment.newNext(context.idGenerator.next(), [
          currentSegments[i],
          currentSegments[i + length],
        ]),
      );
    }
    currentSegments = merged;
  }
  return currentSegments;
}

description:
Creates new segments from the specific range of `context.segmentsList`.

When `context.segmentsList` is `[[a, b], [c, d], [e, f]]`, `begin` is `0`, and
`end` is `-1`, this creates `[g, h]`. This `g` is from `a`, `c`, and `e`.
This `h` is from `b`, `d`, and `f`.
@param {ForkContext} context An instance.
@param {number} begin The first index of the previous segments.
@param {number} end The last index of the previous segments.
@param {Function} create A factory function of new segments.
@returns {CodePathSegment[]} New segments.

code:
function makeSegments(context, begin, end, create) {
  const list = context.segmentsList;

  const normalizedBegin = begin >= 0 ? begin : list.length + begin;
  const normalizedEnd = end >= 0 ? end : list.length + end;

  const segments = [];

  for (let i = 0; i < context.count; ++i) {
    const allPrevSegments = [];

    for (let j = normalizedBegin; j <= normalizedEnd; ++j) {
      allPrevSegments.push(list[j][i]);
    }

    segments.push(create(context.idGenerator.next(), allPrevSegments));
  }

  return segments;
}

description:
@param {IdGenerator} idGenerator An identifier generator for segments.
@param {ForkContext|null} upper An upper fork context.
@param {number} count A number of parallel segments.

code:
constructor(idGenerator, upper, count) {
    this.idGenerator = idGenerator;
    this.upper = upper;
    this.count = count;
    this.segmentsList = [];
  }

get reachable() {
    const segments = this.head;

    return segments.length > 0 && segments.some(isReachable);
  }

description:
Replaces the head segments with given segments.
The current head segments are removed.
@param {CodePathSegment[]} segments Segments to add.
@returns {void}

code:
replaceHead(segments) {
    assert(
      segments.length >= this.count,
      `${segments.length} >= ${this.count}`,
    );

    this.segmentsList.splice(-1, 1, mergeExtraSegments(this, segments));
  }

description:
Creates the root fork context.
@param {IdGenerator} idGenerator An identifier generator for segments.
@returns {ForkContext} New fork context.

code:
static newRoot(idGenerator) {
    const context = new ForkContext(idGenerator, null, 1);

    context.add([CodePathSegment.newRoot(idGenerator.next())]);

    return context;
  }

description:
Adds segments into this context.
The added segments become the head.
@param {CodePathSegment[]} segments Segments to add.
@returns {void}

code:
add(segments) {
    assert(
      segments.length >= this.count,
      `${segments.length} >= ${this.count}`,
    );

    this.segmentsList.push(mergeExtraSegments(this, segments));
  }

description:
Creates an empty fork context preceded by a given context.
@param {ForkContext} parentContext The parent fork context.
@param {boolean} forkLeavingPath A flag which shows inside of `finally` block.
@returns {ForkContext} New fork context.

code:
static newEmpty(parentContext, forkLeavingPath) {
    return new ForkContext(
      parentContext.idGenerator,
      parentContext,
      (forkLeavingPath ? 2 : 1) * parentContext.count,
    );
  }

description:
Adds all segments of a given fork context into this context.
@param {ForkContext} context A fork context to add.
@returns {void}

code:
addAll(context) {
    assert(context.count === this.count);

    const source = context.segmentsList;

    for (let i = 0; i < source.length; ++i) {
      this.segmentsList.push(source[i]);
    }
  }

next() {
    this.n = (1 + this.n) | 0;

    /* c8 ignore start */
    if (this.n < 0) {
      this.n = 1;
    } /* c8 ignore stop */

    return this.prefix + this.n;
  }

function normalizeIndent(strings) {
  const codeLines = strings[0].split('\n');
