@template {Record<string, any>} Props
@param {'sync' | 'async'} mode
@param {import('svelte').Component<Props>} component
@param {{ props?: Omit<Props, '$$slots' | '$$events'>; context?: Map<any, any>; idPrefix?: string }} options
